const d = $input.first().json.body;
const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');
const euro = (v) => new Intl.NumberFormat('nl-NL', { style: 'currency', currency: 'EUR' }).format(Number(v ?? 0));
const dateFmt = (s) => s ? new Intl.DateTimeFormat('nl-NL', { dateStyle: 'long' }).format(new Date(s)) : '—';
const vatRate = (v) => new Intl.NumberFormat('nl-NL', { minimumFractionDigits: Number.isInteger(Number(v ?? 0)) ? 0 : 2, maximumFractionDigits: 2 }).format(Number(v ?? 0));
const from = d.from ?? {};
const companyName = from.companyName ?? '';
const companyEmail = from.email ?? '';
const companyWeb = from.websiteUrl ?? '';
const companyAddr = from.address ?? '';
const companyKvk = from.kvkNumber ?? '';
const companyVat = from.vatNumber ?? '';
const companyIban = from.iban ?? '';
const companyPhone = from.phone ?? '';
const footerText = d.defaults?.footerText ?? '';
const termsText = d.defaults?.termsText ?? '';
const vatRows = Array.isArray(d.vatBreakdown) && d.vatBreakdown.length > 0 ? d.vatBreakdown.map((entry) => `<tr><td>${esc(vatRate(entry.vat_rate))}%</td><td>${esc(String(entry.invoice_count ?? 0))}</td><td>${euro(entry.total_ex_vat)}</td><td>${euro(entry.total_vat)}</td><td>${euro(entry.total_inc_vat)}</td></tr>`).join('') : '<tr><td colspan="5">Geen gegevens</td></tr>';
const invoiceRows = Array.isArray(d.invoices) && d.invoices.length > 0 ? d.invoices.map((invoice) => `<tr><td>${esc(invoice.invoice_number)}</td><td>${esc(invoice.client_name)}</td><td>${esc(invoice.project_name ?? '—')}</td><td>${esc(dateFmt(invoice.paid_at ?? invoice.report_date))}</td><td>${euro(invoice.subtotal)}</td><td>${euro(invoice.vat_amount)}</td><td>${euro(invoice.total_amount)}</td></tr>`).join('') : '<tr><td colspan="7">Geen betaalde facturen in deze periode.</td></tr>';
const html = `<!DOCTYPE html><html lang="nl"><head><meta charset="UTF-8"/><style>*,*::before,*::after{box-sizing:border-box}body{font-family:Arial,sans-serif;font-size:12px;line-height:1.6;color:#1f2937;padding:36px;background:#fff}.header{display:flex;justify-content:space-between;gap:24px;padding-bottom:20px;border-bottom:3px solid #111827;margin-bottom:24px}.brand{font-size:24px;font-weight:700;color:#111827}.muted{font-size:11px;color:#6b7280}.doc-title{font-size:28px;font-weight:800;color:#111827;text-align:right}.meta-table,.table{width:100%;border-collapse:collapse}.meta-table td{padding:2px 0;font-size:11px}.meta-table td:first-child{color:#6b7280;padding-right:16px}.cards{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:24px}.card{border:1px solid #e5e7eb;border-radius:10px;padding:14px;background:#f9fafb}.card .label{font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#6b7280;margin-bottom:6px}.card .value{font-size:16px;font-weight:700;color:#111827}.note{display:grid;grid-template-columns:1fr 1fr;gap:12px;padding:14px 16px;background:#eff6ff;border:1px solid #bfdbfe;border-radius:10px;margin-bottom:24px}.note div{font-size:12px}.section{margin-bottom:24px}.section h2{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#4b5563;margin-bottom:10px}.table th,.table td{padding:8px 10px;border-bottom:1px solid #e5e7eb;font-size:12px;text-align:left;vertical-align:top}.table th{background:#f9fafb;font-size:10px;text-transform:uppercase;letter-spacing:.08em;color:#6b7280}.table td:last-child,.table th:last-child{text-align:right}.footer{margin-top:28px;padding-top:12px;border-top:1px solid #e5e7eb;font-size:10px;color:#6b7280;display:flex;justify-content:space-between;gap:24px}.footer .right{text-align:right}</style></head><body><div class="header"><div><div class="brand">${esc(companyName)}</div><div class="muted">${esc(companyWeb)}${companyWeb && companyEmail ? ' · ' : ''}${esc(companyEmail)}</div></div><div><div class="doc-title">Maandoverzicht ${esc(d.monthLabelLong ?? '')} ${esc(String(d.year ?? ''))}</div><table class="meta-table"><tr><td>Gegenereerd op</td><td>${esc(dateFmt(d.generatedAt))}</td></tr><tr><td>Filter</td><td>Alleen betaalde facturen</td></tr><tr><td>Periodebasis</td><td>Betaaldatum</td></tr></table></div></div><div class="cards"><div class="card"><div class="label">Aantal facturen</div><div class="value">${esc(String(d.invoiceCount ?? 0))}</div></div><div class="card"><div class="label">Ontvangen ex BTW</div><div class="value">${euro(d.totalExVat)}</div></div><div class="card"><div class="label">BTW</div><div class="value">${euro(d.totalVat)}</div></div><div class="card"><div class="label">Ontvangen incl BTW</div><div class="value">${euro(d.totalIncVat)}</div></div></div><div class="note"><div><strong>Periode</strong><br/>${esc(d.period?.startDate ?? '')} t/m ${esc(d.period?.endDateExclusive ?? '')} (exclusief einddatum)</div><div><strong>Bedrijfsgegevens</strong><br/>${esc(companyName)}${companyIban ? `<br/>IBAN ${esc(companyIban)}` : ''}${companyKvk ? `<br/>KVK ${esc(companyKvk)}` : ''}${companyVat ? `<br/>BTW ${esc(companyVat)}` : ''}</div></div><div class="section"><h2>BTW-uitsplitsing</h2><table class="table"><thead><tr><th>BTW-tarief</th><th>Aantal</th><th>Ex BTW</th><th>BTW</th><th>Incl BTW</th></tr></thead><tbody>${vatRows}</tbody></table></div><div class="section"><h2>Factuurdetails</h2><table class="table"><thead><tr><th>Factuur</th><th>Klant</th><th>Project</th><th>Betaaldatum</th><th>Ex BTW</th><th>BTW</th><th>Incl BTW</th></tr></thead><tbody>${invoiceRows}</tbody></table></div>${termsText ? `<div class="section"><h2>Notities</h2><div class="muted">${esc(termsText)}</div></div>` : ''}<div class="footer"><div>${esc(companyName)}${companyAddr ? `<br/>${esc(companyAddr)}` : ''}<br/>${esc(companyEmail)}${companyPhone ? ` · ${esc(companyPhone)}` : ''}</div><div class="right">${companyKvk ? `KVK ${esc(companyKvk)}<br/>` : ''}${companyVat ? `BTW ${esc(companyVat)}<br/>` : ''}Maandoverzicht ${esc(d.monthLabelLong ?? '')} ${esc(String(d.year ?? ''))}${footerText ? `<br/>${esc(footerText)}` : ''}</div></div></body></html>`;
return [{ json: { ...d, html } }];
